class Solution {
public:
    int binarySearch(vector<int>& nums, int target) {
        if (target > nums[nums.size() - 1]) {
            return -1;
        }
        int left = 0, right = nums.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] == target) {
                return mid;
            } else if (nums[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        // BUG: Returning -1 for out of bounds target value
        return -1;
    }
};

