# -*- coding: utf-8 -*-
# Problem Title: Binary Search: Edge Case Error
# Author: [Your Name]
# Date: [Current Date]

class Solution:
    def binarySearch(self, nums: list[int], target: int) -> int:
        if target < nums[0]:
            return -1
        if target > nums[-1]:
            return -1
        left = 0
        right = len(nums) - 1
        while left <= right:
            mid = left + (right - left) // 2
            if nums[mid] == target:
                return mid
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return -1

if __name__ == '__main__':
    nums = list(map(int, input().split()))
    target = int(input())
    solution = Solution()
    print(solution.binarySearch(nums, target))

